'use strict';

var $RangeError = require('es-errors/range');
var $TypeError = require('es-errors/type');

var ToIndex = require('./ToIndex');
var TypedArrayElementSize = require('./TypedArrayElementSize');

var isTypedArray = require('is-typed-array');
var typedArrayByteOffset = require('typed-array-byte-offset');
var typedArrayLength = require('typed-array-length');



module.exports = function ValidateAtomicAccess(typedArray, requestIndex) {
	if (!isTypedArray(typedArray)) {
		throw new $TypeError('Assertion failed: `typedArray` must be a TypedArray');
	}

	var length = typedArrayLength(typedArray); 

	var accessIndex = ToIndex(requestIndex); 

	

	if (accessIndex >= length) {
		throw new $RangeError('index out of range'); 
	}

	var elementSize = TypedArrayElementSize(typedArray); 

	var offset = typedArrayByteOffset(typedArray); 

	return (accessIndex * elementSize) + offset; 
};
